#include<bits/stdc++.h>
using namespace std;
string s;
bool f(string s){
	if(s.size()<6||s.size()>12)return 0;
	bool a=false,b=false,c=false,d=false;
	for(int i=0;i<s.size();i++){
		if((s[i]>='A'&&s[i]<='Z'))a=true;
		else if((s[i]>='a'&&s[i]<='z'))b=true;
        else if(s[i]>='0'&&s[i]<='9')d=true;
		else if((s[i]=='!'||s[i]=='@'||s[i]=='#'||s[i]=='$'))c=true;
		else return false;
	}return a&&b&&c;
}
int main(void) {
	string t;getline(cin,t);
	string s="";
	for(char c:t){
		if(c==','){
			if(f(s))cout<<s<<'\n';
			s="";
		}else s+=c;
	}
	if(f(s))cout<<s;
	return false;
}
